"use client";

import Link from "next/link";
import EventNoteIcon from "@mui/icons-material/EventNote";
import LogoutIcon from "@mui/icons-material/Logout";
import ReceiptLongIcon from "@mui/icons-material/ReceiptLong";
import {
  Box,
  Button,
  Divider,
  Drawer,
  List,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Toolbar,
  Typography
} from "@mui/material";

import { drawerWidth } from "@/lib/mui-theme";

type Props = {
  currentPath: string;
  desktop: boolean;
  mobileOpen: boolean;
  plannerHref: string;
  onCloseMobile: () => void;
  onSignOut: () => Promise<void>;
};

export function SidebarNav({
  currentPath,
  desktop,
  mobileOpen,
  plannerHref,
  onCloseMobile,
  onSignOut
}: Props) {
  const items = [
    { key: "planner", label: "Planner", href: plannerHref, icon: <ReceiptLongIcon fontSize="small" /> },
    { key: "activity", label: "Activity", href: "/activity", icon: <EventNoteIcon fontSize="small" /> }
  ];

  const content = (
    <Box sx={{ display: "flex", flexDirection: "column", height: "100%" }}>
      <Toolbar>
        <Typography variant="h6" component="span">
          Expenses
        </Typography>
      </Toolbar>
      <Divider />
      <List sx={{ px: 1.5, py: 1 }}>
        {items.map((item) => {
          const active = currentPath.startsWith(item.href);
          return (
            <ListItemButton
              key={item.key}
              component={Link}
              href={item.href}
              prefetch
              selected={active}
              onClick={onCloseMobile}
              sx={{ borderRadius: 2, mb: 0.5 }}
            >
              <ListItemIcon sx={{ minWidth: 36 }}>{item.icon}</ListItemIcon>
              <ListItemText primary={item.label} />
            </ListItemButton>
          );
        })}
      </List>
      <Box sx={{ mt: "auto", p: 2 }}>
        <Button
          variant="outlined"
          fullWidth
          startIcon={<LogoutIcon />}
          onClick={() => void onSignOut()}
          sx={{ justifyContent: "flex-start" }}
        >
          Sign out
        </Button>
      </Box>
    </Box>
  );

  if (desktop) {
    return (
      <Drawer
        variant="permanent"
        PaperProps={{ sx: { width: drawerWidth, boxSizing: "border-box", borderRight: "1px solid", borderColor: "divider" } }}
      >
        {content}
      </Drawer>
    );
  }

  return (
    <Drawer
      variant="temporary"
      open={mobileOpen}
      onClose={onCloseMobile}
      ModalProps={{ keepMounted: true }}
      PaperProps={{ sx: { width: drawerWidth, boxSizing: "border-box" } }}
    >
      {content}
    </Drawer>
  );
}
